"use client";

import { useEffect, useState } from "react";

export default function StudioRoute() {
  const [mounted, setMounted] = useState(false);

  useEffect(() => {
    setMounted(true);
  }, []);

  if (!mounted) {
    return (
      <div
        style={{
          height: "100vh",
          display: "flex",
          alignItems: "center",
          justifyContent: "center",
          background: "#FAFAF8",
        }}
      >
        Loading Studio...
      </div>
    );
  }

  const { StudioLayout } = require("@/studio/StudioLayout");
  return <StudioLayout />;
}
